/**
 * Listing HTTP API 路由 (M4)
 * 注册到 OD server.ts 的 /api/listing/* 路径下。
 * Reference: PRD §6.2 M4, OD apps/daemon/src/chat-routes.ts
 */
import type { Router, Request, Response } from 'express';
import { readFileSync, writeFileSync, existsSync, mkdirSync, rmSync } from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';

/** Safely extract a single string from Express req.params */
function param(req: Request, name: string): string {
  const v = req.params[name];
  return Array.isArray(v) ? v[0] ?? '' : v ?? '';
}
import type {
  ListingGenerateRequest,
  ListingRunStatus,
  ListingImageStatus,
  ListingProductInput,
  ListingOutput,
} from '@open-design/contracts';
import { listListingSkills, loadListingSkill, buildListingPrompt } from './skill-loader.js';
import { parseListingOutput } from './tag-parser.js';
import { generateListing } from './listing-generate.js';
import { processImageQueue, regenerateSingleImage, generateImage as generateImageDirect } from './listing-images.js';
import {
  getListingRun,
  updateListingRun,
  listListingRuns,
  getListingImage,
  listListingImages,
  createListingRun,
  createListingImage,
  getKeywordLibrary,
  saveKeywordCategory,
  deleteKeywordCategory,
  listPromptTemplates,
  savePromptTemplate,
  deletePromptTemplate,
  type KeywordItem,
} from './listing-db.js';

// ─── 数据目录解析（与 db.ts 一致） ──────────────────

function resolveDataDir(): string {
  const root = process.env.OD_WORKSPACE_ROOT || process.cwd();
  const override = process.env.OD_DATA_DIR;
  const dir = override ? path.resolve(override) : path.join(root, '.od');
  if (!existsSync(dir)) mkdirSync(dir, { recursive: true });
  return dir;
}

const DATA_DIR = resolveDataDir();

// 模块加载时从文件恢复
// ─── HTML 生成 ─────────────────────────────────────────
function esc(s: string): string { return s?.replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;') || ''; }

function imgTag(filename: string, alt: string): string {
  return '<img src="' + esc(filename) + '.png" alt="' + esc(alt) + '" loading="lazy" />';
}

function buildListingHtml(productName: string, output: Record<string, unknown> | undefined, images: Array<{ tag: string; status: string; imageBase64?: string }>): string {
  const o = output || {} as any;
  const imgMap = new Map(images.map(i => [i.tag, i]));
  const titleA = o.titleA?.text || '';
  const mi = (tag: string) => imgMap.has(tag) ? tag : "";
  const textDesc = o.textDesc || '';
  const details = o.details || [];
  const shots = o.videoScript?.shots || [];

  const CSS = `:root{--bg:#faf9f7;--panel:#fdfcfa;--border:#e1e5eb;--text:#1a1916;--muted:#74716b;--accent:#c96442;--accent-soft:#f5d8cb;--radius:8px;--sans:Inter,system-ui,sans-serif;--mono:JetBrains Mono,monospace}
*{box-sizing:border-box;margin:0;padding:0}body{font-family:var(--sans);background:var(--bg);color:var(--text);line-height:1.6}
.hero{background:linear-gradient(rgba(0,0,0,.25),rgba(0,0,0,.1)),url("data:image/png;base64,") center/cover no-repeat;padding:60px 24px;text-align:center;border-radius:0 0 24px 24px;margin-bottom:24px;position:relative}
.hero h1{font-size:24px;font-weight:700;margin-bottom:8px;color:#fff;text-shadow:0 2px 8px rgba(0,0,0,.3)}
.hero p{font-size:14px;color:rgba(255,255,255,.85);max-width:600px;margin:0 auto;text-shadow:0 1px 4px rgba(0,0,0,.2)}
.section{margin-bottom:24px}.section-title{font-size:16px;font-weight:600;margin-bottom:12px;display:flex;align-items:center;gap:6px}
.card{background:var(--panel);border:1px solid var(--border);border-radius:var(--radius);padding:16px;box-shadow:0 1px 2px rgba(0,0,0,.04);transition:box-shadow .2s}
.card:hover{box-shadow:0 4px 12px rgba(0,0,0,.08)}
.tag{display:inline-block;font-size:11px;padding:2px 8px;border-radius:99px;background:var(--accent-soft);color:var(--accent);margin:2px;font-weight:500}
img{width:100%;height:auto;border-radius:6px;display:block}
.img-placeholder{aspect-ratio:1;display:flex;align-items:center;justify-content:center;background:var(--bg);border:2px dashed var(--border);border-radius:var(--radius);color:var(--muted);font-size:24px}
.title-grid{display:grid;grid-template-columns:1fr 1fr;gap:12px}
.title-block{padding:8px 0}.title-block h3{font-size:14px;margin-bottom:4px}
.visual-grid{display:grid;grid-template-columns:repeat(4,1fr);gap:10px}
.visual-grid .card{padding:8px}.visual-grid h4{font-size:11px;margin-bottom:4px;color:var(--muted)}
table{width:100%;border-collapse:collapse;font-size:12px}
th,td{border:1px solid var(--border);padding:8px 10px;text-align:left}
th{background:var(--bg);font-weight:600}
.detail-grid{display:grid;grid-template-columns:repeat(3,1fr);gap:12px}
.detail-card{text-align:center}
.detail-card h4{font-size:12px;margin-bottom:6px;color:var(--text)}
.detail-card p{font-size:11px;color:var(--muted);margin-top:4px}
@media(max-width:768px){.detail-grid{grid-template-columns:repeat(2,1fr)}}
.desc-card pre{font-family:var(--mono);font-size:13px;white-space:pre-wrap;line-height:1.7;color:var(--text)}
.footer{text-align:center;color:var(--muted);font-size:11px;margin-top:32px;padding:16px;border-top:1px solid var(--border)}
@media(max-width:768px){.title-grid{grid-template-columns:1fr}.visual-grid{grid-template-columns:repeat(2,1fr)}.detail-row{grid-template-columns:1fr}}
`;

  let html = '<!DOCTYPE html><html lang="zh-CN"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>' + esc(productName) + '</title><style>' + CSS + '</style></head><body>';

  // Hero
  html += '<div class="hero"><h1>' + esc(productName) + '</h1><p>AI 驱动的电商 Listing 工作台 · ' + new Date().toLocaleString('zh-CN') + ' 生成</p></div>';

  // 1. 标题
  html += '<div class="section"><div class="section-title">📝 标题</div><div class="title-grid">';
  html += '<div class="title-block"><h3>标题 A</h3><p>' + esc(titleA) + '</p>';
  if (o.titleA?.tags) {
    Object.entries(o.titleA.tags as Record<string,string>).forEach(([k,v]) => { if(v) html += '<span class="tag">'+esc(k)+':'+esc(v)+'</span>'; });
  }
  html += '</div>';
  if (titleB) {
    html += '<div class="title-block"><h3>标题 B</h3><p>' + esc(titleB) + '</p>';
    if (o.titleB?.tags) {
      Object.entries(o.titleB.tags as Record<string,string>).forEach(([k,v]) => { if(v) html += '<span class="tag">'+esc(k)+':'+esc(v)+'</span>'; });
    }
    html += '</div>';
  }
  html += '</div></div>';

  // 2. 视觉展示 (视频封面 + 主图ABC 四栏)
  html += '<div class="section"><div class="section-title">🖼 视觉展示</div><div class="visual-grid">';
  html += '<div class="card"><h4>🎬 视频封面</h4>' + imgTag('VIDEO_COVER', '视频封面') + '</div>';
  html += '<div class="card"><h4>A · 卖点放大</h4>' + imgTag(mi('MAIN_A'), '主图A') + '</div>';
  html += '<div class="card"><h4>B · 场景代入</h4>' + imgTag(mi('MAIN_B'), '主图B') + '</div>';
  html += '<div class="card"><h4>C · 极简纯净</h4>' + imgTag(mi('MAIN_C'), '主图C') + '</div>';
  html += '</div></div>';

  // 3. 视频脚本
  if (shots.length) {
    html += '<div class="section"><div class="section-title">🎬 视频拍摄脚本</div><div class="card"><table>';
    html += '<tr><th>镜头</th><th>时长</th><th>画面内容</th><th>引用卖点</th></tr>';
    shots.forEach((s: any) => {
      html += '<tr><td><strong>' + esc(s.name) + '</strong></td><td>' + esc(s.duration) + '</td><td>' + esc(s.content) + '</td><td>' + esc(s.reference) + '</td></tr>';
    });
    html += '</table></div></div>';
  }

  // 4. 产品描述
  if (textDesc) {
    html += '<div class="section"><div class="section-title">📝 产品描述</div><div class="card desc-card"><pre>' + esc(textDesc) + '</pre></div></div>';
  }

  // 5. 详情图 (上下排列, 左图右文)
  if (details.length) {
    html += '<div class="section"><div class="section-title">🖼 详情图</div><div class="detail-grid">';
    details.forEach((d: any, i: number) => {
      html += '<div class="card detail-card">';
      html += '<h4>图' + (i+1) + ' · ' + esc(d.overlay || '') + '</h4>';
      html += imgTag(mi('DETAIL_' + (i+1)), '详情图'+(i+1));
      if (d.desc) html += '<p>' + esc(d.desc || '') + '</p>';
      html += '</div>';
    });
    html += '</div></div>';
  }

  html += '<div class="footer">ShopAgent Listing Workbench · ' + new Date().toISOString().slice(0,10) + '</div></body></html>';
  return html;
}

// ─── 路由注册 ──────────────────────────────────────────

export function registerListingRoutes(router: Router): void {
  // GET /api/listing/skills
  router.get('/api/listing/skills', (_req: Request, res: Response) => {
    try {
      const skills = listListingSkills();
      res.json(skills);
    } catch (err) {
      res.status(500).json({ error: 'Failed to list skills' });
    }
  });

  // POST /api/listing/generate
  router.post('/api/listing/generate', async (req: Request, res: Response) => {
    try {
      const body = req.body as ListingGenerateRequest;
      if (!body.skillId || !body.product?.productName || !body.product?.surfaceKeywords) {
        res.status(400).json({ error: 'Missing required fields: skillId, product.productName, product.surfaceKeywords' });
        return;
      }

      // 检查 Accept header 决定 SSE vs JSON
      const acceptSse = req.headers.accept?.includes('text/event-stream');

      if (acceptSse) {
        res.writeHead(200, {
          'Content-Type': 'text/event-stream',
          'Cache-Control': 'no-cache',
          'Connection': 'keep-alive',
        });

        const sse = (event: string, data: unknown) => {
          res.write(`event: ${event}\ndata: ${JSON.stringify(data)}\n\n`);
        };

        try {
          const result = await generateListing(body, {
            onStatus: (status) => sse('status', { status }),
            onToken: (token) => sse('token', { token }),
            onOutput: (output) => sse('output', output),
          });

          // 触发异步生图
          const refImage = body.product.productImageBase64;
          const imgApiKey = body.imageApiKey || process.env.APIMART_API_KEY || '';
          const imgBaseUrl = body.imageBaseUrl || process.env.APIMART_API_BASE || '';
          const imgModel = body.imageModel || process.env.APIMART_DEFAULT_MODEL || 'gemini-3.1-flash-image-preview';
          if (imgApiKey) {
            processImageQueue(result.runId, refImage, imgApiKey, imgBaseUrl, imgModel, (evt) => {
              sse('image', evt);
            }).catch((err) => {
              sse('error', { error: err instanceof Error ? err.message : String(err) });
            }).finally(() => {
              updateListingRun(result.runId, { status: 'completed' });
              sse('done', { status: 'completed', runId: result.runId });
              res.end();
            });
          } else {
            updateListingRun(result.runId, { status: 'completed' });
            sse('done', { status: 'completed', runId: result.runId });
            res.end();
          }
        } catch (err) {
          const message = err instanceof Error ? err.message : String(err);
          const statusCode = (err as Record<string, unknown>).statusCode as number | undefined;
          sse('error', { error: message, statusCode });
          res.end();
        }
      } else {
        // JSON 响应（先返回 runId，不等待）
        const result = await generateListing(body);
        const refImage = body.product.productImageBase64;
        const imgApiKey = body.imageApiKey || process.env.APIMART_API_KEY || '';
        const imgBaseUrl = body.imageBaseUrl || process.env.APIMART_API_BASE || '';
        const imgModel = body.imageModel || process.env.APIMART_DEFAULT_MODEL || 'gemini-3.1-flash-image-preview';
        if (imgApiKey) {
          processImageQueue(result.runId, refImage, imgApiKey, imgBaseUrl, imgModel).catch((err) => {
            console.error('Image queue error:', err);
          }).finally(() => {
            updateListingRun(result.runId, { status: 'completed' });
          });
        } else {
          updateListingRun(result.runId, { status: 'completed' });
        }
        res.json({ runId: result.runId, status: 'images_generating' });
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      const statusCode = (err as Record<string, unknown>).statusCode as number | undefined;
      res.status(statusCode ?? 500).json({ error: message });
    }
  });

  // GET /api/listing/runs/:id
  router.get('/api/listing/runs/:id', (req: Request, res: Response) => {
    const run = getListingRun(param(req, 'id'));
    if (!run) { res.status(404).json({ error: 'Run not found' }); return; }

    const includeImages = req.query?.includeImages === 'true';
    const images = listListingImages(run.id);
    const imageStatuses: ListingImageStatus[] = images.map((img) => {
      const base: ListingImageStatus = {
        id: img.id,
        moduleTag: img.moduleTag,
        model: img.model,
        status: img.status,
      };
      if (includeImages) {
        (base as Record<string, unknown>).imageBase64 = img.imageBase64 ?? null;
        (base as Record<string, unknown>).imageUrl = img.imageUrl ?? null;
      }
      return base;
    });

    const status: ListingRunStatus = {
      id: run.id,
      status: run.status as ListingRunStatus['status'],
      images: imageStatuses,
    };
    if (run.resultData) status.output = run.resultData;
    if (run.error) status.error = run.error;
    res.json(status);
  });

  // POST /api/listing/runs/:id/images/:imageId/regenerate
  router.post('/api/listing/runs/:id/images/:imageId/regenerate', async (req: Request, res: Response) => {
    try {
      const imageId = param(req, 'imageId');
      const regenBody = req.body as {
        prompt?: string; referenceImageBase64?: string; modelId?: string;
        imageApiKey?: string; imageBaseUrl?: string;
      };

      const image = getListingImage(imageId!);
      if (!image) { res.status(404).json({ error: 'Image not found' }); return; }

      const acceptSse = req.headers.accept?.includes('text/event-stream');
      if (acceptSse) {
        res.writeHead(200, {
          'Content-Type': 'text/event-stream',
          'Cache-Control': 'no-cache',
          'Connection': 'keep-alive',
        });

        const sse = (event: string, data: unknown) => {
          res.write(`event: ${event}\ndata: ${JSON.stringify(data)}\n\n`);
        };

        try {
          await regenerateSingleImage(
            imageId!,
            regenBody.prompt ?? image.prompt,
            regenBody.referenceImageBase64,
            regenBody.imageApiKey || process.env.APIMART_API_KEY || '',
            regenBody.imageBaseUrl || process.env.APIMART_API_BASE || '',
            regenBody.modelId ?? image.model,
            (evt) => sse('image', evt),
          );
          sse('done', { status: 'completed' });
        } catch (err) {
          sse('error', { error: err instanceof Error ? err.message : String(err) });
        }
        res.end();
      } else {
        await regenerateSingleImage(
          imageId!,
          regenBody.prompt ?? image.prompt,
          regenBody.referenceImageBase64,
          regenBody.imageApiKey || process.env.APIMART_API_KEY || '',
          regenBody.imageBaseUrl || process.env.APIMART_API_BASE || '',
          regenBody.modelId ?? image.model,
        );
        res.json({ status: 'completed' });
      }
    } catch (err) {
      const message = err instanceof Error ? err.message : String(err);
      res.status(500).json({ error: message });
    }
  });

  // GET /api/listing/keywords?language=en
  router.get('/api/listing/keywords', (req: Request, res: Response) => {
    const lang = (req.query.language as string) || 'en';
    try {
      const lib = getKeywordLibrary(lang);
      res.json(lib);
    } catch (err) { res.json({}); }
  });

  // POST /api/listing/keywords — save category
  router.post('/api/listing/keywords', (req: Request, res: Response) => {
    try {
      const { language, category, keywords } = req.body as { language: string; category: string; keywords: KeywordItem[] };
      if (!language || !category) { res.status(400).json({ error: 'language and category required' }); return; }
      saveKeywordCategory(language, category, keywords || []);
      res.json({ ok: true });
    } catch (err) { res.status(400).json({ error: 'Invalid keyword data' }); }
  });

  // DELETE /api/listing/keywords?language=en&category=表层词
  router.delete('/api/listing/keywords', (req: Request, res: Response) => {
    const lang = (req.query.language as string) || 'en';
    const cat = req.query.category as string;
    if (!cat) { res.status(400).json({ error: 'category required' }); return; }
    deleteKeywordCategory(lang, cat);
    res.json({ ok: true });
  });

  // GET /api/listing/prompts
  router.get('/api/listing/prompts', (_req: Request, res: Response) => {
    try {
      const rows = listPromptTemplates();
      res.json(rows.map(r => ({
        id: r.id,
        name: r.name,
        category: r.category,
        tags: JSON.parse(r.tags),
        prompt: r.prompt,
        bestModel: r.best_model,
        createdAt: r.created_at,
      })));
    } catch (err) {
      res.status(500).json({ error: 'Failed to list prompts' });
    }
  });

  // POST /api/listing/prompts
  router.post('/api/listing/prompts', (req: Request, res: Response) => {
    try {
      const { name, category, tags, prompt, bestModel } = req.body as Record<string, unknown>;
      if (!name || !category || !prompt) {
        res.status(400).json({ error: 'name, category, prompt required' });
        return;
      }
      const row = savePromptTemplate({
        name: name as string,
        category: category as string,
        tags: Array.isArray(tags) ? tags as string[] : undefined,
        prompt: prompt as string,
        bestModel: bestModel as string | undefined,
      });
      res.json({ id: row.id, ok: true });
    } catch (err) {
      res.status(400).json({ error: 'Invalid prompt data' });
    }
  });

  // DELETE /api/listing/prompts/:id
  router.delete('/api/listing/prompts/:id', (req: Request, res: Response) => {
    const id = param(req, 'id');
    if (!id) { res.status(400).json({ error: 'id required' }); return; }
    const deleted = deletePromptTemplate(id);
    if (!deleted) { res.status(404).json({ error: 'Prompt not found' }); return; }
    res.json({ ok: true });
  });

  // GET /api/listing/runs
  router.get('/api/listing/runs', (req: Request, res: Response) => {
    const projectId = req.query.projectId as string | undefined;
    const runs = listListingRuns(projectId);
    res.json(runs.map((r) => ({
      id: r.id,
      skillId: r.skillId,
      platform: r.platform,
      status: r.status,
      createdAt: r.createdAt,
    })));
  });

  // POST /api/listing/build-prompt — 浏览器调用，获取组装好的 prompt
  router.post('/api/listing/build-prompt', (req: Request, res: Response) => {
    try {
      const { skillId, product } = req.body as { skillId: string; product: ListingProductInput };
      const skill = loadListingSkill(skillId);
      if (!skill) { res.status(400).json({ error: 'Skill not found' }); return; }
      const prompt = buildListingPrompt(skill, product);
      res.json({ prompt });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /api/listing/parse-output — 浏览器调用，解析 LLM 输出并存储
  router.post('/api/listing/parse-output', (req: Request, res: Response) => {
    try {
      const { rawOutput, skillId, product } = req.body as { rawOutput: string; skillId: string; product: ListingProductInput };
      const skill = loadListingSkill(skillId);
      const platform = skill?.platform || 'shopee';
      const runId = createListingRun({ skillId, platform, productData: product });
      const output = parseListingOutput(rawOutput);
      updateListingRun(runId, { resultData: output, status: 'completed' });
      createImagePlaceholders(runId, output);
      res.json(output);
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /api/listing/images/generate — 直接生图代理（前端调用）
  router.post('/api/listing/images/generate', async (req: Request, res: Response) => {
    try {
      const { prompt, referenceImageBase64, apiKey, baseUrl, model } = req.body as {
        prompt: string; referenceImageBase64?: string;
        apiKey: string; baseUrl: string; model: string;
      };
      if (!prompt || !apiKey || !baseUrl) {
        res.status(400).json({ error: 'Missing prompt, apiKey, or baseUrl' }); return;
      }
      const result = await generateImageDirect(apiKey, model, prompt, baseUrl, referenceImageBase64);
      res.json({ ok: true, imageBase64: result });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });

  function createImagePlaceholders(runId: string, output: ListingOutput): void {
    const model = process.env.APIMART_DEFAULT_MODEL || 'gemini-3.1-flash-image-preview';
    const mods: Array<{ tag: string; prompt: string }> = [
      { tag: 'MAIN_A', prompt: output.mainA.prompt },
      { tag: 'MAIN_B', prompt: output.mainB.prompt },
      { tag: 'MAIN_C', prompt: output.mainC.prompt },
    ];
    for (const d of output.details) { if (d.prompt) mods.push({ tag: `DETAIL_${d.index}`, prompt: d.prompt }); }
    if (output.videoScript.coverPrompt) mods.push({ tag: 'VIDEO_COVER', prompt: output.videoScript.coverPrompt });
    for (const m of mods) { if (m.prompt) createListingImage({ runId, moduleTag: m.tag, model, prompt: m.prompt }); }
  }

  // POST /api/listing/test-connection
  router.post('/api/listing/test-connection', async (req: Request, res: Response) => {
    try {
      const { type, apiKey, baseUrl } = req.body as { type: string; apiKey: string; baseUrl?: string };
      const url = baseUrl ?? (
        type === 'deepseek' ? 'https://api.deepseek.com/v1' :
        type === 'apimart' ? (process.env.APIMART_API_BASE || 'https://api.apimart.ai/v1') :
        ''
      );
      if (!url) { res.status(400).json({ error: 'Unknown connection type' }); return; }

      const resp = await fetch(`${url}/models`, {
        headers: { 'Authorization': `Bearer ${apiKey}` },
      });
      const ok = resp.ok;
      const errorText = ok ? undefined : await resp.text().catch(() => '');
      res.json({ ok, error: errorText?.slice(0, 200) });
    } catch (err) {
      res.json({ ok: false, error: err instanceof Error ? err.message : String(err) });
    }
  });

  // POST /api/listing/save-project — 保存/更新 listing 输出为项目
  router.post('/api/listing/save-project', async (req: Request, res: Response) => {
    try {
      const { productName, productImageBase64, output, imageResults, projectId: existingId } = req.body as {
        productName: string;
        productImageBase64?: string;
        output?: Record<string, unknown>;
        imageResults?: Array<{ tag: string; status: string; imageBase64?: string }>;
        projectId?: string;
      };

      if (!productName) { res.status(400).json({ error: 'productName required' }); return; }

      const projectId = existingId || crypto.randomUUID();
      const projectsDir = path.join(DATA_DIR, 'projects', projectId);

      // 覆盖模式：删除旧目录重建
      if (existingId && existsSync(projectsDir)) {
        rmSync(projectsDir, { recursive: true, force: true });
      }
      mkdirSync(projectsDir, { recursive: true });

      // 写入产品图
      if (productImageBase64) {
        writeFileSync(path.join(projectsDir, 'product.png'), Buffer.from(productImageBase64, 'base64'));
      }

      // 写入生成的图片（PNG 文件，可复用）
      for (const img of (imageResults || [])) {
        if (img.imageBase64) {
          try {
            const b64 = img.imageBase64.replace(/^data:image\/\w+;base64,/, '');
            writeFileSync(path.join(projectsDir, img.tag + '.png'), Buffer.from(b64, 'base64'));
          } catch { /* skip corrupt images */ }
        }
      }

      // 写入 listing 完整 JSON
      writeFileSync(
        path.join(projectsDir, 'listing-output.json'),
        JSON.stringify({ productName, output: output || null, images: imageResults || [], savedAt: new Date().toISOString() }, null, 2),
        'utf-8',
      );

      // 写入 listing HTML 展示页
      writeFileSync(path.join(projectsDir, 'listing.html'), buildListingHtml(productName, output, imageResults || []), 'utf-8');

      // 调用 daemon 内部 API 创建/更新项目
      const daemonPort = process.env.OD_PORT || '7456';
      const apiMethod = existingId ? 'PUT' : 'POST';
      const apiUrl = existingId
        ? `http://127.0.0.1:${daemonPort}/api/projects/${projectId}`
        : `http://127.0.0.1:${daemonPort}/api/projects`;
      const apiRes = await fetch(apiUrl, {
        method: apiMethod,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          ...(existingId ? {} : { id: projectId }),
          name: productName,
          updatedAt: new Date().toISOString(),
        }),
      });

      if (!apiRes.ok) {
        const text = await apiRes.text().catch(() => '');
        res.status(500).json({ error: `Project ${existingId ? 'update' : 'creation'} failed: ${text.slice(0, 200)}` });
        return;
      }

      res.json({ projectId });
    } catch (err) {
      res.status(500).json({ error: err instanceof Error ? err.message : String(err) });
    }
  });
}
